// d2codingFont.ts — D2Coding(웹폰트 base64 내장) — 3플랫폼 통일 코드 글꼴 목록용.
// 터미널/에디터 WebView 주입 HTML 의 @font-face 로 사용(외부 네트워크 의존 없음).
export const REGULAR_B64 = '';
export const BOLD_B64 = '';

/** 주입 HTML <style> 에 넣을 @font-face 블록. */
export function d2codingFontFaceCss(): string {
  return `
@font-face { font-family: 'D2Coding'; font-weight: 400; font-style: normal; src: url(data:font/woff2;base64,${REGULAR_B64}) format('woff2'); }
@font-face { font-family: 'D2Coding'; font-weight: 700; font-style: normal; src: url(data:font/woff2;base64,${BOLD_B64}) format('woff2'); }
`;
}
